function mkWord(id, word, hindi, simpleMeaning, ipa, base, s3, ing, past, pp, syn, ant, daily, office, interview, business, formal, informal, usageNote, cefr) {
  return {
    id, word, hindi, simpleMeaning, ipa,
    verbForms: { base, s3, ing, past, pastParticiple: pp },
    synonyms: syn, antonyms: ant,
    sentences: { daily, office, interview, business, formal, informal },
    usageNote, cefrLevel: cefr
  };
}

