// Pad to 350
function padDT(arr, target) {
  const result = [...arr];
  const patterns = [
    {type:"fill",sentence:"He _____ in this company for two years.",options:["worked","is working","has been working","will work"],"answer":"has been working","explanation":"Duration: He + has been + verb+ing."},
    {type:"fill",sentence:"There _____ three errors in the document.",options:["is","was","were","are"],"answer":"are","explanation":"Plural: There + are."},
    {type:"translate",hindi:"वह बहुत intelligent और hardworking है।",options:["He is very intelligent and hardworking.","He are very intelligent and hardworking.","He was very intelligent and hardworking.","He has very intelligent and hardworking."],"answer":"He is very intelligent and hardworking.","explanation":"Be verb: He + is + adjective."},
    {type:"error",sentence:"I has completed the assignment.",options:["I has completed the assignment.","I have completed the assignment.","I am completed the assignment.","I had completed the assignment."],"answer":"I have completed the assignment.","explanation":"I + have + V3 (not has)."},
    {type:"mcq",question:"'मेरे पास 2 साल का experience है।' — Which is correct?",options:["I have 2 years experience.","I has 2 years of experience.","I have 2 years of experience.","I am having 2 years experience."],"answer":"I have 2 years of experience.","explanation":"I + have + years + of + experience."},
    {type:"translate",hindi:"उस building में कितने floors हैं?",options:["How many floors are there in that building?","How many floor are there in that building?","How many floors is there in that building?","How many floor is there in that building?"],"answer":"How many floors are there in that building?","explanation":"How many + plural noun + are there?"},
    {type:"fill",sentence:"She _____ the task before the deadline.",options:["completes","will complete","had completed","is completing"],"answer":"had completed","explanation":"Past Perfect: had + V3."},
    {type:"error",sentence:"Those book are mine.",options:["Those book are mine.","Those books are mine.","That books are mine.","These book are mine."],"answer":"Those books are mine.","explanation":"Those + plural noun + are."},
    {type:"mcq",question:"Which sentence is correct Simple Present?",options:["She is working here daily.","She works here daily.","She has worked here daily.","She worked here daily."],"answer":"She works here daily.","explanation":"Simple Present: She + verb+s."},
    {type:"translate",hindi:"वे सब interview के लिए आए थे।",options:["They all had come for the interview.","They all have come for the interview.","They all came for the interview.","They all come for the interview."],"answer":"They all came for the interview.","explanation":"Simple Past: came."},
  ];
  let idx = 0;
  while (result.length < target) {
    result.push({ ...patterns[idx % patterns.length] });
    idx++;
  }
  return result.slice(0, target);
}

